import{_ as l,o as a,c as e,a2 as o}from"./chunks/framework.Pywvta2k.js";const q=JSON.parse('{"title":"黄帝内经","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/01-先秦两汉/01-黄帝内经.md","filePath":"tcm-data/01-先秦两汉/01-黄帝内经.md","lastUpdated":1781084559000}'),r={name:"tcm-data/01-先秦两汉/01-黄帝内经.md"};function i(n,t,s,h,d,u){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="黄帝内经" tabindex="-1">黄帝内经 <a class="header-anchor" href="#黄帝内经" aria-label="Permalink to &quot;黄帝内经&quot;">​</a></h1><blockquote><p>中医理论的奠基之作，&quot;医家之宗&quot; 成书：战国至西汉（约公元前5世纪-公元1世纪），非一人一时之作</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>成书年代</strong>：战国至西汉，历时数百年，经多代医家增补</li><li><strong>篇卷数量</strong>：《素问》24卷81篇 + 《灵枢》24卷81篇 = <strong>162篇</strong></li><li><strong>体例形式</strong>：黄帝问、岐伯答（君臣问答体）</li><li><strong>学术地位</strong>：中医四大经典之首，&quot;不读《内经》者，不可言知医&quot;</li></ul><h3 id="内容框架" tabindex="-1">内容框架 <a class="header-anchor" href="#内容框架" aria-label="Permalink to &quot;内容框架&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">部分</th><th style="text-align:left;">核心内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>《素问》</strong></td><td style="text-align:left;">阴阳五行、脏腑经络、病因病机、诊法治则、五运六气</td></tr><tr><td style="text-align:left;"><strong>《灵枢》</strong>（旧称《针经》）</td><td style="text-align:left;">经络腧穴、针刺技法、气血运行、九针形态</td></tr></tbody></table><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-阴阳学说-——-中医世界观" tabindex="-1">1. 阴阳学说 —— 中医世界观 <a class="header-anchor" href="#_1-阴阳学说-——-中医世界观" aria-label="Permalink to &quot;1. 阴阳学说 —— 中医世界观&quot;">​</a></h3><blockquote><p><strong>「阴阳者，天地之道也，万物之纲纪，变化之父母，生杀之本始，神明之府也。」</strong>（素问·阴阳应象大论）</p></blockquote><ul><li>人体健康 = 阴阳平衡</li><li>疾病 = 阴阳失衡</li><li>治疗 = 调整阴阳</li></ul><h3 id="_2-五行学说-——-系统模型" tabindex="-1">2. 五行学说 —— 系统模型 <a class="header-anchor" href="#_2-五行学说-——-系统模型" aria-label="Permalink to &quot;2. 五行学说 —— 系统模型&quot;">​</a></h3><blockquote><p><strong>「木生火，火生土，土生金，金生水，水生木」</strong><strong>「木克土，土克水，水克火，火克金，金克木」</strong></p></blockquote><p>五脏配五行：肝（木）→ 心（火）→ 脾（土）→ 肺（金）→ 肾（水）</p><h3 id="_3-脏腑经络-——-人体解剖生理学" tabindex="-1">3. 脏腑经络 —— 人体解剖生理学 <a class="header-anchor" href="#_3-脏腑经络-——-人体解剖生理学" aria-label="Permalink to &quot;3. 脏腑经络 —— 人体解剖生理学&quot;">​</a></h3><p><strong>五脏</strong>（藏精气而不泻）：</p><ul><li>心：君主之官，主血脉、主神明</li><li>肝：将军之官，主疏泄、藏血</li><li>脾：仓廪之官，主运化、统血</li><li>肺：相傅之官，主气、司呼吸</li><li>肾：作强之官，藏精、主水</li></ul><p><strong>六腑</strong>（传化物而不藏）：</p><ul><li>胆、胃、大肠、小肠、膀胱、三焦</li></ul><p><strong>十二经络</strong>：手足三阴三阳经，气血运行的通道</p><h3 id="_4-病因病机" tabindex="-1">4. 病因病机 <a class="header-anchor" href="#_4-病因病机" aria-label="Permalink to &quot;4. 病因病机&quot;">​</a></h3><blockquote><p><strong>「夫百病之始生也，皆生于风雨寒暑，阴阳喜怒，饮食居处，大惊卒恐。」</strong></p></blockquote><p><strong>三因论</strong>：</p><ul><li>外因：风、寒、暑、湿、燥、火（六淫）</li><li>内因：喜、怒、忧、思、悲、恐、惊（七情）</li><li>不内外因：饮食、劳倦、外伤</li></ul><h3 id="_5-诊法-——-四诊合参" tabindex="-1">5. 诊法 —— 四诊合参 <a class="header-anchor" href="#_5-诊法-——-四诊合参" aria-label="Permalink to &quot;5. 诊法 —— 四诊合参&quot;">​</a></h3><blockquote><p><strong>「望而知之谓之神，闻而知之谓之圣，问而知之谓之工，切脉而知之谓之巧。」</strong></p></blockquote><ul><li>望诊：观面色、舌象、形态</li><li>闻诊：听声音、嗅气味</li><li>问诊：问症状、病史</li><li>切诊：切脉、触诊</li></ul><h3 id="_6-五运六气-——-时间医学" tabindex="-1">6. 五运六气 —— 时间医学 <a class="header-anchor" href="#_6-五运六气-——-时间医学" aria-label="Permalink to &quot;6. 五运六气 —— 时间医学&quot;">​</a></h3><blockquote><p><strong>「夫五运阴阳者，天地之道也。」</strong></p></blockquote><ul><li>天干化五运：甲己土、乙庚金、丙辛水、丁壬木、戊癸火</li><li>地支合六气：子午少阴、丑未太阴、寅申少阳、卯酉阳明、辰戌太阳、巳亥厥阴</li><li><strong>临床价值</strong>：根据运气推演预判当年多发病、指导方药选择</li></ul><h3 id="_7-治未病-——-预防医学" tabindex="-1">7. 治未病 —— 预防医学 <a class="header-anchor" href="#_7-治未病-——-预防医学" aria-label="Permalink to &quot;7. 治未病 —— 预防医学&quot;">​</a></h3><blockquote><p><strong>「圣人不治已病治未病，不治已乱治未乱。」</strong></p></blockquote><ul><li>未病先防</li><li>既病防变</li><li>瘥后防复</li></ul><h3 id="_8-上古天真论-——-生命规律" tabindex="-1">8. 上古天真论 —— 生命规律 <a class="header-anchor" href="#_8-上古天真论-——-生命规律" aria-label="Permalink to &quot;8. 上古天真论 —— 生命规律&quot;">​</a></h3><blockquote><p><strong>「女子七岁，肾气盛，齿更发长……五七阳明脉衰，面始焦，发始堕；六七三阳脉衰于上，面皆焦，发始白；七七任脉虚，天癸竭。」</strong><strong>「丈夫八岁，肾气实，发长齿更……五八肾气衰，发堕齿槁；六八阳气衰竭于上，面焦，发鬓颁白；八八天癸竭，精少，肾脏衰。」</strong></p></blockquote><hr><h2 id="三、核心治则与治法" tabindex="-1">三、核心治则与治法 <a class="header-anchor" href="#三、核心治则与治法" aria-label="Permalink to &quot;三、核心治则与治法&quot;">​</a></h2><h3 id="治则" tabindex="-1">治则 <a class="header-anchor" href="#治则" aria-label="Permalink to &quot;治则&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">治则</th><th style="text-align:left;">原文</th><th style="text-align:left;">应用</th></tr></thead><tbody><tr><td style="text-align:left;">治病求本</td><td style="text-align:left;">「治病必求于本」</td><td style="text-align:left;">不治标而治本</td></tr><tr><td style="text-align:left;">逆从正反</td><td style="text-align:left;">「寒者热之，热者寒之」</td><td style="text-align:left;">正治法</td></tr><tr><td style="text-align:left;">标本缓急</td><td style="text-align:left;">「急则治其标，缓则治其本」</td><td style="text-align:left;">分清主次</td></tr><tr><td style="text-align:left;">补虚泻实</td><td style="text-align:left;">「实则泻之，虚则补之」</td><td style="text-align:left;">扶正祛邪</td></tr></tbody></table><h3 id="治疗手段" tabindex="-1">治疗手段 <a class="header-anchor" href="#治疗手段" aria-label="Permalink to &quot;治疗手段&quot;">​</a></h3><ul><li><strong>针法</strong>：《灵枢》详论九针、针刺手法、得气</li><li><strong>灸法</strong>：「针所不为，灸之所宜」</li><li><strong>药法</strong>：开方药先河（详于《神农本草经》）</li><li><strong>导引按跷</strong>：气功导引、推拿按摩</li></ul><hr><h2 id="四、经典名言精选" tabindex="-1">四、经典名言精选 <a class="header-anchor" href="#四、经典名言精选" aria-label="Permalink to &quot;四、经典名言精选&quot;">​</a></h2><h3 id="论生命" tabindex="-1">论生命 <a class="header-anchor" href="#论生命" aria-label="Permalink to &quot;论生命&quot;">​</a></h3><blockquote><p><strong>「正气存内，邪不可干。」</strong><strong>「邪之所凑，其气必虚。」</strong><strong>「精神内守，病安从来。」</strong></p></blockquote><h3 id="论阴阳" tabindex="-1">论阴阳 <a class="header-anchor" href="#论阴阳" aria-label="Permalink to &quot;论阴阳&quot;">​</a></h3><blockquote><p><strong>「阴平阳秘，精神乃治；阴阳离决，精气乃绝。」</strong><strong>「重阴必阳，重阳必阴。」</strong></p></blockquote><h3 id="论天人" tabindex="-1">论天人 <a class="header-anchor" href="#论天人" aria-label="Permalink to &quot;论天人&quot;">​</a></h3><blockquote><p><strong>「人以天地之气生，四时之法成。」</strong><strong>「夫四时阴阳者，万物之根本也。所以圣人春夏养阳，秋冬养阴，以从其根。」</strong></p></blockquote><h3 id="论诊法" tabindex="-1">论诊法 <a class="header-anchor" href="#论诊法" aria-label="Permalink to &quot;论诊法&quot;">​</a></h3><blockquote><p><strong>「善诊者，察色按脉，先别阴阳。」</strong><strong>「得神者昌，失神者亡。」</strong></p></blockquote><h3 id="论治法" tabindex="-1">论治法 <a class="header-anchor" href="#论治法" aria-label="Permalink to &quot;论治法&quot;">​</a></h3><blockquote><p><strong>「大毒治病，十去其六；常毒治病，十去其七；小毒治病，十去其八；无毒治病，十去其九。谷肉果菜，食养尽之，无使过之，伤其正也。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><h3 id="直接传承" tabindex="-1">直接传承 <a class="header-anchor" href="#直接传承" aria-label="Permalink to &quot;直接传承&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">后世典籍</th><th style="text-align:left;">受《内经》影响</th></tr></thead><tbody><tr><td style="text-align:left;">《伤寒杂病论》</td><td style="text-align:left;">继承&quot;治病必求于本&quot;，创六经辨证</td></tr><tr><td style="text-align:left;">《四圣心源》（黄元御）</td><td style="text-align:left;">发挥&quot;阴阳五行&quot;&quot;一气周流&quot;理论</td></tr><tr><td style="text-align:left;">《圆运动的古中医学》（彭子益）</td><td style="text-align:left;">以&quot;圆运动&quot;阐释天人阴阳升降</td></tr><tr><td style="text-align:left;">金元四大家</td><td style="text-align:left;">各从《内经》取一偏而发扬</td></tr></tbody></table><h3 id="现代应用" tabindex="-1">现代应用 <a class="header-anchor" href="#现代应用" aria-label="Permalink to &quot;现代应用&quot;">​</a></h3><ul><li>中医基础理论教材的框架来源</li><li>五运六气在疫病预测中的应用</li><li>治未病思想指导现代养生</li><li>经络理论指导针灸临床</li></ul><h3 id="黄元御与《内经》的关系" tabindex="-1">黄元御与《内经》的关系 <a class="header-anchor" href="#黄元御与《内经》的关系" aria-label="Permalink to &quot;黄元御与《内经》的关系&quot;">​</a></h3><p>黄元御自称&quot;黄帝、岐伯、越人、仲景四圣之心&quot;，认为《内经》建立了&quot;天人合一、一气周流&quot;的完整体系，其<strong>四圣心源</strong>中的&quot;左升右降、中土枢转&quot;模型直接脱胎于《内经》的阴阳升降理论。</p><hr><h2 id="六、学习顺序建议" tabindex="-1">六、学习顺序建议 <a class="header-anchor" href="#六、学习顺序建议" aria-label="Permalink to &quot;六、学习顺序建议&quot;">​</a></h2><ol><li><strong>先读白话版</strong>：徐文兵《黄帝内经家用说明书》或《黄帝内经说什么》系列</li><li><strong>再读选篇</strong>：《素问》上古天真论、四气调神大论、阴阳应象大论、灵兰秘典论</li><li><strong>再读全本</strong>：以倪海厦或王洪图注释本为佳</li><li><strong>后读经典注家</strong>：全元起、王冰、吴崑、张介宾《类经》</li></ol><hr><p><em>本条目为精简框架版，后续可扩展至各章节精读、方剂出处、历代注家对比等内容。</em></p>',67)])])}const c=l(r,[["render",i]]);export{q as __pageData,c as default};
